Use MAUI's `Window` lifecycle events combined with `Preferences` for lightweight persistence:

```csharp
// NotePage.xaml.cs
public partial class NotePage : ContentPage
{
    private const string DraftKey = "note_draft";

    public NotePage()
    {
        InitializeComponent();

        // Restore draft when page is created
        NoteEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    protected override void OnAppearing()
    {
        base.OnAppearing();

        // Subscribe to lifecycle events
        var window = Application.Current?.Windows.FirstOrDefault();
        if (window is not null)
        {
            window.Deactivated += OnAppBackgrounded;
            window.Resumed += OnAppResumed;
        }
    }

    protected override void OnDisappearing()
    {
        base.OnDisappearing();

        var window = Application.Current?.Windows.FirstOrDefault();
        if (window is not null)
        {
            window.Deactivated -= OnAppBackgrounded;
            window.Resumed -= OnAppResumed;
        }
    }

    private void OnAppBackgrounded(object? sender, EventArgs e)
    {
        // Save draft immediately when app goes to background
        Preferences.Set(DraftKey, NoteEditor.Text ?? string.Empty);
    }

    private void OnAppResumed(object? sender, EventArgs e)
    {
        // Restore draft when app returns (handles process termination case)
        NoteEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    // Call this when the user explicitly saves/discards
    private void ClearDraft()
    {
        Preferences.Remove(DraftKey);
    }
}
```

**Key points:**

- **`Window.Deactivated`** fires when the app goes to the background — save here.
- **`Window.Resumed`** fires when the app returns to the foreground.
- **`Preferences`** is ideal for small text; for large drafts, use `FileSystem.AppDataDirectory` with file I/O instead.
- Always **unsubscribe** in `OnDisappearing` to avoid leaks.
- Call `ClearDraft()` when the user saves or discards the note so stale drafts don't reappear.
